var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"크윽......!","JPN":"くうっ……","ENG":"Argh...","TWN":"嗚……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"좋아! 쓰러트렸다!","JPN":"よし！　倒したぞ！","ENG":"Great! She's down!","TWN":"很好！打倒了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"하하! 애송이 주제에 날뛰면 이렇게 당하는 거란다!","JPN":"はは！　小娘のくせに暴れるからこんな目に遭うんだ！","ENG":"Hah hah! This is what happens when you're overconfident about yourself, kid.","TWN":"哈哈！乳臭未乾的小鬼頭，下場就是這樣！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"경찰의 엘리트 카운터라고 하더니 생각보다 별거 아니잖아?","JPN":"警察のエリートカウンターだと聞いたんだが、大したことないじゃないか！","ENG":"As it turns out, the so-called elite police Counter was never a serious threat.","TWN":"這樣竟然是警察中的精英制裁者，比我想像得還要弱啊？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"전투 경험은 전혀 없는 것 같은데?","JPN":"戦闘経験はゼロのようだが？","ENG":"She seemed completely inexperienced in real combat, no?","TWN":"好像完全沒有戰鬥經驗的樣子？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"신수 님이 안 계셨어도 우리 힘만으로 잡을 수 있었던 거 아냐?","JPN":"神獣がいなくても、俺たちの力だけで捕まえられたんじゃないか？","ENG":"We didn't even need the divine beast to get her.","TWN":"就算沒有神獸大人，光靠我們的力量就能抓住她了吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"경솔한 언행은 삼가라. 모든 것이 예언자님의 뜻대로 돌아가는 것뿐이야.","JPN":"軽はずみな言動は慎め。\\nすべては預言者様の意のままに回っているんだ。","ENG":"Be careful with your rash remarks. Everything is working out as the great prophet planned.","TWN":"切忌輕率言行。一切都只是如預言者大人所料。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"다른 경찰들이 오기 전에 특수 엘릭서 붕괴체를 데리고 빠르게 철수한다!","JPN":"警察が来る前に特殊エリクサー崩壊体を連れてさっさと撤収するぞ！","ENG":"We'll take the unique Elixir Collapser and retreat before reinforcement arrives!","TWN":"在其他警察過來之前，快帶著特殊聖水崩壞體撤退！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어, 어딜...... 가......!","JPN":"い、行かせる……ものか……","ENG":"W-where do you think... you're going?","TWN":"想、想去……哪裡……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내가...... 있는 이상...... 범죄자들은...... 놓치지...... 않아......","JPN":"私が……いる限り……犯罪者は……逃さ……ない……","ENG":"You can't... get away... Not when... I'm... around...","TWN":"只要……有我在……絕不會……放過……罪犯……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"몸도 못 가누면서 무슨 소리를 하는 거야? 꼬마 경찰 아가씨.","JPN":"体もまともに動かせないくせに何を言ってるんだ？\\n警察のお嬢さん。","ENG":"Listen to yourself, talking big when you can't even sit up straight, little lady officer.","TWN":"妳的身體都不聽使喚了，還有什麼好說的？警察小姐。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"다음부터는 어른들 일에 함부로 끼지 말라고!","JPN":"次からは大人のやることに首を突っ込まないことだな！","ENG":"Stay out of the grown-ups' business in the future, okay?","TWN":"下次別隨便插手大人們的事！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"다음이 있다면 말이지만. 크크큭!","JPN":"まあ、次があればの話だが。クククッ！","ENG":"That is, if there's future for you. Hee hee hee!","TWN":"如果妳還有下一次的話，嘿嘿！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이, 이 자식들......","JPN":"こ、こいつら……","ENG":"Y-you bastards...","TWN":"你、你們這群傢伙……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"우왓! 뭐, 뭐야?","JPN":"うわっ！　な、何だ？","ENG":"Wah! W-what the hell?","TWN":"唔哇！什、什麼？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"에, 엘카노 주교님께서 차와 함께 날아갔어!","JPN":"え、エルカノ司教が車と一緒に飛ばされたぞ！","ENG":"A car knocked Bishop Elcano into the air!","TWN":"啊，埃爾卡諾主教大人和車一起飛走了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"뺑소니인가?","JPN":"ひき逃げか？","ENG":"Wait…","TWN":"是逃跑了嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"아냐, 이건......!","JPN":"違う、これは……","ENG":"Wasn't that a police car?","TWN":"不、那是……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"범죄자들은 당장 무기를 버리고 무릎을 꿇는다. 실시!","JPN":"犯罪者たちはただちに武器を捨てて跪け。","ENG":"Drop your weapons and kneel on the ground. We won't say this twice.","TWN":"罪犯們馬上扔掉武器跪下！立刻照做！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"투항하지 않으면 지금부터 강경진압에 들어가겠다.","JPN":"投降しないのであれば、今から強硬鎮圧を開始する。","ENG":"Do it now, or we'll do it for you.","TWN":"不投降的話，我們現在就會開始強制鎮壓。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"자, 잠깐 저거! 블랙타이드 용병대잖아?","JPN":"あ、あれは！　ブラックタイド傭兵隊じゃないか？","ENG":"W-wait! I know them! They're the Black Tide mercenaries!","TWN":"等、等一下，那是！那不是黑潮傭兵隊嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"어, 어떡하지? 싸워야 하나?","JPN":"ど、どうするんだ？　戦うべきか？","ENG":"W-what should we do? Should we fight?","TWN":"哎呀，怎麼辦啊？得和他們打嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"저 끔찍한 놈들이랑 싸우긴 뭘 싸워?! ","JPN":"あのおぞましいやつらと戦うだと！？","ENG":"We don't stand a chance against them! ","TWN":"笨蛋！那群傢伙就和戰鬥兵器一樣啊。打什麼打？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"계란처럼 박살 날일 있냐?!","JPN":"卵みたいに潰されたいのか？","ENG":"Unless you want to be crushed like eggs!","TWN":"這和以卵擊石有什麼兩樣？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"주교님도 벌써 일어나서 달아나고 있잖아! 너희들도 뛰어!","JPN":"司教も立ち上がって逃げてるじゃないか！　お前たちも走れ！","ENG":"Look, the bishop's already up and fleeing! Run, you fools!","TWN":"主教大人不早就逃跑了嗎！你們也快逃啊！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"나, 난 먼저 성지로 귀환하겠다!","JPN":"わ、私は先に聖地に帰還するぞ！","ENG":"I-I'll fall back to the sanctum for now.","TWN":"我、我就先回聖地了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"......너희들은 그 특수 붕괴체 여자애를 잊지 말고 챙겨오도록! 알겠나?!!","JPN":"……あの特殊崩壊体の娘を連れてくるのを忘れるな！　いいか！？","ENG":"You bring that unique Collapser girl with you on your way back! Do you hear me?","TWN":"……你們別忘了那個特殊崩壞體的女孩，記得帶上她！知道了嗎？！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"어, 어? 주교님? 같이 가요!","JPN":"え、えっ？　司教？　待ってください！","ENG":"Err, err? Bishop! Wait for us!","TWN":"啊，嗯？主教大人？帶我們一起走啊！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"주교님!!","JPN":"司教！！","ENG":"Bishop!","TWN":"主教大人！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};